// Validate Meta WhatsApp webhook signature.
// X-Hub-Signature-256 = sha256=<hex>; HMAC of raw body with WHATSAPP_APP_SECRET.
// CRITICAL: signature is over RAW BYTES Meta sent. JSON re-serialisation breaks it.
// Webhook node must have options.rawBody=true so the bytes survive.
//
// Failure modes returned (in this order of precedence):
//   1. reason='raw_body_unavailable'  — neither raw-body path was populated by the
//                                       Webhook node. Distinct diagnostic — fix the
//                                       webhook config, don't chase HMAC math.
//   2. valid=false  (no `reason` set) — HMAC mismatch on a body we DID read.
//                                       Real signature failure (spoof or wrong secret).
//   3. valid=true                     — body authenticated.
//
// NOTE on n8n stdlib access: n8n's Code node sandbox blocks `require()` of
// stdlib modules BY DEFAULT. The n8n service must be started with env var
// NODE_FUNCTION_ALLOW_BUILTIN including 'crypto' (or '*') for the require
// below to resolve. See .claude/rules/n8n-workflows.md rule #12 and the
// n8n service env block in infrastructure/docker-compose.yml.
//   - `Buffer` IS a default Node.js global (no require, no allowlist needed)
//   - `crypto` is NOT a default global — must be require()'d AND allowlisted

const crypto = require('crypto');
const item = $input.item;
const headers = (item.json && item.json.headers) || {};
const sigHeader = headers['x-hub-signature-256'] || headers['X-Hub-Signature-256'] || '';
const secret = $env.WHATSAPP_APP_SECRET || '';

// Two raw-body access paths only. NO third re-serialisation fallback —
// silent fall-through to a known-broken path would obscure debugging.
// If neither path matches, we surface a distinct 'raw_body_unavailable'
// diagnostic so the operator fixes the webhook config rather than chasing
// a phantom HMAC mismatch.
let rawBody = null;
if (item.binary && item.binary.data && item.binary.data.data) {
  // Webhook node with options.rawBody=true → body in binary.data as base64
  rawBody = Buffer.from(item.binary.data.data, 'base64');
} else if (typeof item.json.body === 'string') {
  // Some n8n versions surface raw body as a string on json.body
  rawBody = Buffer.from(item.json.body, 'utf8');
}

if (rawBody === null) {
  // Fail closed with a distinct signal. Downstream Postgres node uses
  // `reason` to write a clear error_message='raw_body_unavailable' row
  // to workflow_errors instead of the (misleading) HMAC-mismatch text.
  return [{
    json: {
      valid: false,
      reason: 'raw_body_unavailable',
      received_signature_prefix: sigHeader.slice(0, 24),
      raw_body_length: 0,
      body_parsed: null
    }
  }];
}

const computed = crypto.createHmac('sha256', secret).update(rawBody).digest('hex');

let valid = false;
const prefix = 'sha256=';
if (sigHeader.startsWith(prefix) && secret.length > 0) {
  const received = sigHeader.slice(prefix.length);
  if (received.length === computed.length) {
    try {
      valid = crypto.timingSafeEqual(
        Buffer.from(received, 'hex'),
        Buffer.from(computed, 'hex')
      );
    } catch (e) {
      valid = false;
    }
  }
}

let bodyParsed = null;
try {
  bodyParsed = JSON.parse(rawBody.toString('utf8'));
} catch (e) {
  bodyParsed = item.json.body || null;
}

return [{
  json: {
    valid,
    body_parsed: bodyParsed,
    received_signature_prefix: sigHeader.slice(0, 24),
    raw_body_length: rawBody.length
  }
}];
